def sum_of_gcds(k: int, dimensions: List[int]) -> int:
    MOD = 10**9 + 7

    # Function to compute the GCD of a list of numbers
    def gcd_list(lst: List[int]) -> int:
        return reduce(gcd, lst)

    # Initialize the result
    total_sum = 0

    # Iterate over all possible combinations of indices
    for i in range(1, dimensions[0] + 1):
        for j in range(1, dimensions[1] + 1):
            for k in range(1, dimensions[2] + 1):
                if k == 3:
                    # For 3D, iterate over the third dimension
                    for l in range(1, dimensions[3] + 1):
                        total_sum = (total_sum + gcd(i, j, k, l)) % MOD
                elif k == 2:
                    # For 2D, only iterate over the second dimension
                    total_sum = (total_sum + gcd(i, j, k)) % MOD
                else:
                    # For 1D, only iterate over the first dimension
                    total_sum = (total_sum + gcd(i, j)) % MOD

    return total_sum

