def can_paint_pebbles(n, k, a):
    # Calculate the maximum number of pebbles any color can have in a pile
    max_pebbles = sum(a) // k

    # Check if we can distribute pebbles such that the difference between any two piles for any color is at most 1
    for pile in a:
        if pile > max_pebbles:
            return "NO"

    # If possible, paint the pebbles
    painted = [0] * n
    for i in range(n):
        remaining_pebbles = a[i]
        for j in range(1, k + 1):
            if remaining_pebbles >= j:
                painted[i] = j
                remaining_pebbles -= j
                break

    # Output the result
    if "NO" in painted:
        print("NO")
    else:
        print("YES")
        for pile in painted:
            print(pile)

