    # Initialize the set of possible letters
    possible_letters = set('abcdefghijklmnopqrstuvwxyz')

    # Initialize the count of excessive shocks
    excessive_shocks = 0

    # Process each action
    for _ in range(n - 1):
        action = input().strip()

