            # Valentin got an electric shock
            word = action[2:]
            for letter in word:
                if letter in possible_letters:
                    possible_letters.remove(letter)
        elif action[0] == '.':
            # Valentin didn't get an electric shock
            word = action[2:]
            for letter in word:
                if letter in possible_letters:
                    possible_letters.remove(letter)
        else:
            # Valentin made a guess
            guess = action[2]
            if guess in possible_letters:
                # If the guess is correct, we can avoid excessive shocks
                break
            else:
                # Otherwise, we need to count an excessive shock
                excessive_shocks += 1

    return excessive_shocks

