            word = action[1]
            for char in word:
                absent.add(char)
        elif action[0] == '.':
            word = action[1]
            for char in word:
                present.add(char)
        else:  # action[0] == '?'
            guess = action[1]

            # If the guessed letter is in absent, it means it cannot be the selected letter
            if guess in absent:
                continue

            # If the guessed letter is not in present, it means it must be the selected letter
            if guess not in present:
                return len(present) + len(absent)

    # If no guess is made, return 0
    return 0

