def count_excessive_shocks(n, actions):
    # Dictionary to store the frequency of each letter
    letter_count = {}

    # Initialize the set of possible letters
    possible_letters = set('abcdefghijklmnopqrstuvwxyz')

    # Iterate over each action
    for action in actions:
        if action[0] == '!':
            # If the action is an electric shock, remove the corresponding letter from possible_letters
            word = action[2:]
            for char in word:
                if char in letter_count:
                    letter_count[char] -= 1
                    if letter_count[char] == 0:
                        possible_letters.remove(char)
        elif action[0] == '.':
            # If the action is not an electric shock, add the corresponding letter to possible_letters
            word = action[2:]
            for char in word:
                if char not in letter_count:
                    letter_count[char] = 0
                letter_count[char] += 1
                if char in possible_letters:
                    possible_letters.remove(char)
        else:
            # If the action is a guess, check if it matches the unique letter
            guess = action[2]
            if guess in possible_letters:
                # If the guess matches the unique letter, return the number of possible letters minus 1
                return len(possible_letters) - 1

    # If no guess is made, return the number of possible letters minus 1
    return len(possible_letters) - 1

