from typing import List

def count_pairs(n: int, l: int, r: int, a: List[int]) -> int:
    # Sort the array to use the two-pointer technique
    a.sort()

    count = 0
    left, right = 0, n - 1

    while left < right:
        current_sum = a[left] + a[right]

        if current_sum >= l and current_sum <= r:
            count += right - left
            left += 1
        elif current_sum < l:
            left += 1
        else:
            right -= 1

    return count

