def find_min_capture(cities, connections):
    def bfs(start):
        queue = [start]
        visited = set([start])
        level = 0
        while queue:
            next_level = []
            for city in queue:
                for neighbor in connections[city]:
                    if neighbor not in visited:
                        visited.add(neighbor)
                        next_level.append(neighbor)
            queue = next_level
            level += 1
        return len(visited)

    important_cities = set(cities)
    max_distance = 0
    for city in important_cities:
        distance = bfs(city)
        if distance > max_distance:
            max_distance = distance
    return max_distance - 1

