def dfs(graph, node, visited, stack):
    visited[node] = True
    for neighbor in graph[node]:
        if not visited[neighbor]:
            dfs(graph, neighbor, visited, stack)
    stack.append(node)

def dfs_reversed(graph, node, visited, component):
    visited[node] = True
    component.append(node)
    for neighbor in reversed(graph[node]):
        if not visited[neighbor]:
            dfs_reversed(graph, neighbor, visited, component)

def kosaraju(n, graph):
    visited = [False] * n
    stack = []
    for node in range(n):
        if not visited[node]:
            dfs(graph, node, visited, stack)

    visited = [False] * n
    sccs = []
    while stack:
        node = stack.pop()
        if not visited[node]:
            component = []
            dfs_reversed(graph, node, visited, component)
            sccs.append(component)

    return sccs

def min_cities_to_capture(n, edges, important_cities):
    # Build the graph
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u-1].append(v-1)
        graph[v-1].append(u-1)

    # Find SCCs
    sccs = kosaraju(n, graph)

    # Check each SCC
    min_cities = float('inf')
    for scc in sccs:
        if any(city in important_cities for city in scc):
            # Check if all important cities in the SCC can be isolated
            isolated = True
            for city in scc:
                if city in important_cities:
                    # Check if there is a path from any important city to another important city in the SCC
                    for other_city in important_cities:
                        if other_city != city and other_city in scc:
                            isolated = False
                            break
                    if not isolated:
                        break

            if isolated:
                # If isolated, check the minimum number of cities to capture
                if len(scc) == len(important_cities):
                    min_cities = 0
                else:
                    min_cities = 1

    return min_cities if min_cities != float('inf') else -1

