def drop_balls(n, m, k, grid, columns):
    # Initialize the result list
    results = []

    for c in columns:
        # Start from the first row
        x = 0
        y = c - 1

        # Continue until the ball leaves the grid
        while 0 <= x < n and 0 <= y < m:
            # If the ball hits the boundary, reverse its direction
            if y == 0 and grid[x][y] == 1:
                grid[x][y] = 3
            elif y == m - 1 and grid[x][y] == 3:
                grid[x][y] = 1
            else:
                # Move to the next cell based on the current direction
                if grid[x][y] == 1:
                    y += 1
                elif grid[x][y] == 2:
                    x += 1
                elif grid[x][y] == 3:
                    y -= 1

            # Update the current position
            x += 1

    # Output the final positions of the balls
    for result in results:
        print(result, end=' ')

