def can_achieve_k(n, k, a):
    # Check if the sum of the list can be reduced to k
    if sum(a) - k < 0:
        return "NO"

    # Check if we can make all elements equal to k
    for i in range(n):
        if a[i] != k:
            # If any element is not equal to k, check if we can reduce it to k
            if sum(a) - a[i] < 0:
                return "NO"
            # Reduce the current element to k
            sum(a) -= a[i]
            a[i] = k

    return "YES"

