    # Calculate the initial sum of each column
    col_sums = [0] * m
    for i, row in enumerate(intervals):
        for start, end in row:
            for j in range(start - 1, end):
                col_sums[j] += 1

    # Sort intervals by the number of zeros in each column
    sorted_intervals = sorted(intervals, key=lambda row: sum(1 for start, end in row for j in range(start - 1, end)))

    # Try to change zeros to ones to maximize quality
    for row, row_intervals in enumerate(sorted_intervals):
        for start, end in row_intervals:
            for j in range(start - 1, end):
                if grid[row][j] == 0:
                    grid[row][j] = 1
                    col_sums[j] += 1

    # Calculate the quality of the grid
    quality = sum(col_sum ** 2 for col_sum in col_sums)
    return quality

