    for _ in range(n):
        k = int(input())
        intervals.append([list(map(int, input().split())) for _ in range(k)])

    max_quality = 0

    def calculate_quality(floor):
        col_sums = [0] * m
        for row in floor:
            for interval in row:
                col_sums[interval[0] - 1] += 1
        return sum(x**2 for x in col_sums)

    def backtrack(row, floor):
        nonlocal max_quality
        if row == n:
            max_quality = max(max_quality, calculate_quality(floor))
            return

        for col in range(1, m + 1):
            if col not in [interval[0] - 1 for interval in intervals[row]]:
                floor[row][0] = [col]
                backtrack(row + 1, floor)
                floor[row][0] = []

    backtrack(0, [[[]] * m for _ in range(n)])
    return max_quality

