from collections import defaultdict

def bfs(graph, start):
    visited = [False] * len(graph)
    queue = [start]
    visited[start] = True
    level = {start: 0}

    while queue:
        current = queue.pop(0)
        for neighbor in graph[current]:
            if not visited[neighbor]:
                visited[neighbor] = True
                queue.append(neighbor)
                level[neighbor] = level[current] + 1

    return level

