def solve(n, m, right_half, edges):
    # Build the adjacency list representation of the graph
    graph = defaultdict(list)
    for u, v in edges:
        graph[u - 1].append(v - 1)

    # Calculate the sum of right half numbers for each subset of left half vertices
    subset_sums = []
    for i in range(1 << n):
        subset_sum = 0
        for j in range(n):
            if (i >> j) & 1:
                subset_sum += right_half[j]
                # Add the sum of right half numbers adjacent to vertices in the subset
                for neighbor in graph[j]:
                    if (i >> neighbor) & 1:
                        subset_sum += right_half[neighbor]
        subset_sums.append(subset_sum)

    # Compute the GCD of all subset sums
    return gcd_of_list(subset_sums)

